  ('immigration-1aab856d-moex-00140', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '某工廠違法排放廢水，公益團體以書面通知促請環境主管機關依職權處理此等情事，而環境 主管機關於書面通知送達之日起 60 日內仍未依法執行者，公益團體在此情形下依法得提起 何種類型行政訴訟？', '["撤銷訴訟", "預防性不作為訴訟", "公益訴訟", "確認訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "7185f513df9b", "answer_pdf_sha1": "13755252dfea", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
