  ('immigration-1aab856d-moex-00145', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '2023年4月，美國國土安全部公布《四年期國土安全檢討》，闡明美國國土安全現今面臨的威脅 及挑戰，已經不同於當初創立國土安全部之情境，因此，在美國國土安全部成立以來便設立五大 核心任務之外，新增第六項國土安全任務，下列何者是美國新增的第六項國土安全任務？', '["打擊各種剝削的犯罪行為及保護受害者", "反制恐怖主義與預防威脅", "確保和管理美國邊境", "確保網路空間及關鍵基礎設施安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00146', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '2023年9月，美國國土安全部公布《2024年國土威脅評估》（HomelandThreatAssessment2024）， 從四個國土安全層面評估威脅，分別是：公共安全、邊境和移民、關鍵基礎設施以及下列那一個 層面？', '["經濟安全", "國防安全", "認知安全", "社會安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00147', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '國土安全之資安層面情資交流，必須持續監控有關資通安全情資，經由四大流程進行進一步篩濾， 再進行不同等級之資通安全事件的處理。此四大流程計有：情資收容、情資彙整、情資分析以及 下列那個流程之處理？', '["情資分類", "情資加值", "情資評估", "情資分發"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00148', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '「資安即國安戰略2.0」提出五大推動策略（TRUST），下列何者不在其中？', '["Talent：培育資安卓越人才，建構聯合作戰機制", "Resilience：提升防護韌性", "Unity：促進資安國際合作，建構內外聯防體系", "Sure：確認威脅來源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00149', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '有關「核恐怖主義」的描述，下列何者錯誤？', '["2009年4月，美國總統歐巴馬提到：核恐怖主義是國際安全的最大威脅之一，並提到美國要 建立一個無核武世界", "恐怖分子和跨國犯罪組織獲取、非法販運核材料，甚至製造核恐怖事件的危險不容忽視", "依據國際原子能總署統計，從1993年到2008年，全球共發生經確認的核材料或其他放射性材 料偷竊、丟失或非授權占有等事件多達1500餘起", "歐巴馬倡議下，2010到2016年每2年舉行「核安全高峰會」（NuclearSecuritySummit），和 核武國家針對其核武設施（核彈頭及飛彈）的維護及安全進行討論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
